// --- types.d.ts ---
export interface ForecastItem {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: string;
  forecast: ForecastItem[];
}

export interface WeatherHookReturn {
  formattedTemp: string;
  weatherIcon: string;
  formattedHumidity: string;
  formattedWind: string;
}

export interface ForecastDayProps {
  item: ForecastItem;
  unit: string;
}


// --- constants.ts ---
export const CONDITION_ICONS: Record<string, string> = {
  Sunny: '☀️',
  Clear: '☀️',
  'Partly Cloudy': '⛅',
  Cloudy: '☁️',
  Rainy: '🌧️',
  Rain: '🌧️',
  Snowy: '❄️',
  Snow: '❄️',
  Thunderstorm: '⛈️',
  Mist: '🌫️',
  Fog: '🌫️',
  Windy: '💨',
};

export const DEFAULT_ICON = '🌡️';


// --- hooks.ts ---
import { useMemo } from 'react';
import { Props, WeatherHookReturn } from './types';
import { CONDITION_ICONS, DEFAULT_ICON } from './constants';

export const useWeather = (props: Props): WeatherHookReturn => {
  const { temperature, unit = 'C', condition, humidity, windSpeed } = props;

  const formattedTemp = useMemo(() => `${Math.round(temperature)}°${unit}`, [temperature, unit]);

  const weatherIcon = useMemo(() => {
    return CONDITION_ICONS[condition] || DEFAULT_ICON;
  }, [condition]);

  const formattedHumidity = useMemo(() => `${humidity}%`, [humidity]);

  const formattedWind = useMemo(() => {
    const windUnit = unit === 'C' ? 'km/h' : 'mph';
    return `${windSpeed} ${windUnit}`;
  }, [windSpeed, unit]);

  return {
    formattedTemp,
    weatherIcon,
    formattedHumidity,
    formattedWind,
  };
};


// --- ForecastDay.tsx ---
import React from 'react';
import { Stack, Text } from '@ggui-ai/design/primitives';
import { ForecastDayProps } from './types';

export const ForecastDay: React.FC<ForecastDayProps> = ({ item, unit }) => {
  return (
    <Stack direction="vertical" align="center" gap={8}>
      <Text 
        variant="label" 
        color="var(--ggui-color-onSurfaceVariant, #52525b)"
        align="center"
      >
        {item.day}
      </Text>

      <Text size="3xl" align="center" aria-hidden="true">
        {item.icon}
      </Text>

      <Stack direction="horizontal" gap={8} align="center" justify="center">
        <Text weight="bold" size="sm">
          {item.high}°
        </Text>
        <Text 
          size="sm" 
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
        >
          {item.low}°
        </Text>
      </Stack>
    </Stack>
  );
};


// --- ui.tsx ---
import React from 'react';
import { Card, Stack, Heading, Text, Box, Divider } from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';
import { Props } from './types';
import { useWeather } from './hooks';
import { ForecastDay } from './ForecastDay';

export const WeatherCard: React.FC<Props> = (props) => {
  const { city, condition, forecast, unit = 'C' } = props;
  const { formattedTemp, weatherIcon, formattedHumidity, formattedWind } = useWeather(props);

  return (
    <Card padding={24} shadow="lg" radius="xl" border={true}>
      <Stack gap={24}>
        {/* Main Header: City and Current Temperature */}
        <Stack direction="horizontal" justify="between" align="center">
          <Stack gap={4}>
            <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
              {city}
            </Heading>
            <Text 
              variant="bodyLarge" 
              color="var(--ggui-color-onSurfaceVariant, #52525b)" 
              weight="medium"
            >
              {condition} {weatherIcon}
            </Text>
          </Stack>
          <Text 
            size="4xl" 
            weight="bold" 
            color="var(--ggui-color-primary-600, #0284c7)"
          >
            {formattedTemp}
          </Text>
        </Stack>

        {/* Weather Details Grid */}
        <CardGrid columns={2} gap={16}>
          <Box 
            padding={16} 
            background="var(--ggui-color-surfaceVariant, #f4f4f5)" 
            borderRadius="var(--ggui-shape-radius-lg, 12px)"
          >
            <Stack gap={4}>
              <Text 
                variant="overline" 
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                HUMIDITY
              </Text>
              <Text 
                size="xl" 
                weight="semibold" 
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {formattedHumidity}
              </Text>
            </Stack>
          </Box>
          <Box 
            padding={16} 
            background="var(--ggui-color-surfaceVariant, #f4f4f5)" 
            borderRadius="var(--ggui-shape-radius-lg, 12px)"
          >
            <Stack gap={4}>
              <Text 
                variant="overline" 
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                WIND
              </Text>
              <Text 
                size="xl" 
                weight="semibold" 
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {formattedWind}
              </Text>
            </Stack>
          </Box>
        </CardGrid>

        <Divider margin={8} />

        {/* 5-Day Forecast Strip */}
        <Stack direction="horizontal" justify="between" align="center">
          {forecast.map((item, index) => (
            <ForecastDay 
              key={`${item.day}-${index}`} 
              item={item} 
              unit={unit} 
            />
          ))}
        </Stack>
      </Stack>
    </Card>
  );
};


// --- render.tsx ---
import { WeatherCard } from './ui';
import { Container } from '@ggui-ai/design/primitives';
import { Props } from './types';

export default function Render(props: Props) {
  return (
    <Container maxWidth="sm" padding={20}>
      <WeatherCard {...props} />
    </Container>
  );
}
